SELECT id, article_type, title, content, author_account, create_time, view_count FROM article WHERE article_type = #{articleType}
AND (
title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%')
) ORDER BY create_time DESC

SELECT id, article_type, title, content, author_account, create_time, view_count
FROM article
WHERE id IN (
    SELECT article_id FROM collection WHERE user_account = #{userAccount}
)

AND (

        title LIKE CONCAT('%', #{keyword}, '%')
        OR content LIKE CONCAT('%', #{keyword}, '%')

)
ORDER BY create_time DESC
